def label_days(days):
    result = []
    for day in days:
        if day % 3 == 0 and day % 7 == 0:
            result.append("Off-Site")
        elif day % 7 == 0:
            result.append("Rest")
        elif day % 3 == 0:
            result.append("Meeting")
        else:
            result.append("Work")
    return result

unit_tests:
import unittest

class TestSolution(unittest.TestCase):
    def test_first_week(self):
        self.assertEqual(label_days([1, 2, 3, 4, 5, 6, 7]),
                         ["Work", "Work", "Meeting", "Work", "Work", "Meeting", "Rest"])

    def test_mixed_days(self):
        self.assertEqual(label_days([21, 14, 15, 16]),
                         ["Off-Site", "Rest", "Meeting", "Work"])

    def test_single_off_site(self):
        self.assertEqual(label_days([42]), ["Off-Site"])

    def test_hidden_empty_list(self):
        self.assertEqual(label_days([]), [])

    def test_hidden_single_work(self):
        self.assertEqual(label_days([1]), ["Work"])

    def test_hidden_all_off_site(self):
        self.assertEqual(label_days([21, 42, 63]), ["Off-Site", "Off-Site", "Off-Site"])

    def test_hidden_full_month(self):
        expected = [
            "Work", "Work", "Meeting", "Work", "Work", "Meeting", "Rest",
            "Work", "Meeting", "Work", "Work", "Meeting", "Work", "Rest",
            "Meeting", "Work", "Work", "Meeting", "Work", "Work", "Off-Site",
            "Work", "Work", "Meeting", "Work", "Work", "Meeting", "Rest",
            "Work", "Meeting", "Work"
        ]
        self.assertEqual(label_days(list(range(1, 32))), expected)

    def test_hidden_multiples_of_seven(self):
        self.assertEqual(label_days([7, 14, 28, 35, 49]),
                         ["Rest", "Rest", "Rest", "Off-Site", "Rest"])

    def test_hidden_multiples_of_three(self):
        self.assertEqual(label_days([3, 6, 9, 12, 18]),
                         ["Meeting", "Meeting", "Meeting", "Meeting", "Meeting"])

if __name__ == '__main__':
    unittest.main()
